/**
 * RegionMapScene — Zoomed-in view of a single region.
 * Shows the region's terrain cells, towns, locations, and fog of war.
 * HTML panel provides navigation controls.
 *
 * @module RegionMapScene
 */

import { Graphics, Container, Text, TextStyle } from 'pixi.js';
import SceneManager from '../core/SceneManager.js';
import EventBus from '../core/EventBus.js';
import DebugLog from '../debug/DebugLog.js';
import WorldState from '../world/WorldState.js';

// ─── Biome colors (same as WorldMapScene) ────────────────────────────────────

const BIOME_COLORS = {
  ocean:         0x1a3a5c,
  frozen_sea:    0x4a7899,
  tundra:        0xc8cabb,
  taiga:         0x2d5a27,
  forest:        0x3a7a2e,
  plains:        0x8aaa44,
  desert:        0xd4a84b,
  jungle:        0x1e6b1e,
  mountain:      0x7a6a5a,
  volcanic:      0x5a2a1a,
  archipelago:   0x2a5a7a,
  // M21: new biomes
  swamp:         0x3d5228,
  crystal_caves: 0x7a6aaa,
  cursed_wastes: 0x5a4a66,
};

// Darker shade for neighboring-region context cells
const NEIGHBOR_DARKEN = 0.45;

function darken(color) {
  const r = Math.floor(((color >> 16) & 0xff) * NEIGHBOR_DARKEN);
  const g = Math.floor(((color >> 8) & 0xff) * NEIGHBOR_DARKEN);
  const b = Math.floor((color & 0xff) * NEIGHBOR_DARKEN);
  return (r << 16) | (g << 8) | b;
}

const CELL_SIZE = 14; // larger cells since we're zoomed in on one region

const LOCATION_COLORS = {
  dungeon:     0x884422,
  cave:        0x776655,
  ruins:       0x8866aa,
  bandit_camp: 0xaa4444,
  shrine:      0x4488cc,
  waypoint:    0x44cc88,
};

export default class RegionMapScene {
  async init({ renderer, regionId } = {}) {
    this._renderer = renderer;
    this._regionId = regionId ?? WorldState.currentRegionId ?? 0;
    this._panel = null;
    this._regionContainer = null;
    this._fogContainer = null;
    this._camera = { x: 0, y: 0, zoom: 1 };
    this._isDragging = false;
    this._dragStart = { x: 0, y: 0 };
    this._dragCameraStart = { x: 0, y: 0 };
    this._dragMoved = false;
    this._resizeUnsub = null;
    this._fogUpdateUnsub = null;

    window.__debug = window.__debug ?? {};
    window.__debug.currentScene = 'regionMap';

    if (!WorldState.world) {
      DebugLog.error('[world] RegionMapScene: no world data — transition to worldMap first');
      SceneManager.transition('worldMap');
      return;
    }

    WorldState.exploreRegion(this._regionId);

    this._buildPixiRegion();
    this._buildHTMLPanel();
    this._bindInput();
    this._centerCamera();

    this._resizeUnsub = EventBus.on('renderer:resize', () => {
      this._centerCamera();
    });
    this._fogUpdateUnsub = EventBus.on('fog:update', () => this._redrawFog());

    DebugLog.info(`[world] RegionMapScene initialized; regionId=${this._regionId}`);
  }

  // ─── PixiJS region map ───────────────────────────────────────────────────────

  _buildPixiRegion() {
    const world = WorldState.world;
    const region = world.regions.find(r => r.id === this._regionId);
    if (!region) return;

    const worldLayer = this._renderer.layers.world;

    this._regionContainer = new Container();
    this._regionContainer.label = 'regionMapContainer';
    worldLayer.addChild(this._regionContainer);

    // Build a set of region cells for fast lookup
    const regionCellSet = new Set(region.cells.map(c => `${c.x},${c.y}`));

    // Find bounding box of the region
    let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
    for (const c of region.cells) {
      if (c.x < minX) minX = c.x;
      if (c.x > maxX) maxX = c.x;
      if (c.y < minY) minY = c.y;
      if (c.y > maxY) maxY = c.y;
    }

    this._regionBounds = { minX, maxX, minY, maxY };

    // Expand by 3 rings for context
    const RING_EXPAND = 3;
    const viewMinX = Math.max(0, minX - RING_EXPAND);
    const viewMaxX = Math.min(world.gridW - 1, maxX + RING_EXPAND);
    const viewMinY = Math.max(0, minY - RING_EXPAND);
    const viewMaxY = Math.min(world.gridH - 1, maxY + RING_EXPAND);

    // ── Terrain cells ──────────────────────────────────────────────────────
    const terrainGfx = new Graphics();

    for (let gy = viewMinY; gy <= viewMaxY; gy++) {
      for (let gx = viewMinX; gx <= viewMaxX; gx++) {
        const cell = world.cells[gy * world.gridW + gx];
        if (!cell) continue;

        const isThisRegion = regionCellSet.has(`${gx},${gy}`);
        let color = BIOME_COLORS[cell.biome] ?? 0x333333;
        if (!isThisRegion) {
          color = darken(color);
        }

        const px = (gx - viewMinX) * CELL_SIZE;
        const py = (gy - viewMinY) * CELL_SIZE;

        terrainGfx.rect(px, py, CELL_SIZE, CELL_SIZE);
        terrainGfx.fill({ color });
      }
    }

    this._regionContainer.addChild(terrainGfx);
    this._viewOffset = { x: viewMinX, y: viewMinY };

    // ── Region border highlight ────────────────────────────────────────────
    const borderGfx = new Graphics();
    for (const c of region.cells) {
      const px = (c.x - viewMinX) * CELL_SIZE;
      const py = (c.y - viewMinY) * CELL_SIZE;

      // Check each of 4 neighbors; if neighbor is not in region → draw border edge
      const dirs = [[-1, 0, 0, 0, 0, CELL_SIZE], [1, 0, CELL_SIZE, 0, CELL_SIZE, CELL_SIZE],
                    [0, -1, 0, 0, CELL_SIZE, 0], [0, 1, 0, CELL_SIZE, CELL_SIZE, CELL_SIZE]];

      for (const [dx, dy, ex1, ey1, ex2, ey2] of dirs) {
        const nx = c.x + dx;
        const ny = c.y + dy;
        if (!regionCellSet.has(`${nx},${ny}`)) {
          borderGfx.moveTo(px + ex1, py + ey1);
          borderGfx.lineTo(px + ex2, py + ey2);
        }
      }
    }
    borderGfx.stroke({ color: 0xc8a020, width: 2, alpha: 0.6 });
    this._regionContainer.addChild(borderGfx);

    // ── Rivers through the region ──────────────────────────────────────────
    if (world.rivers && world.rivers.length > 0) {
      const riverGfx = new Graphics();
      for (const river of world.rivers) {
        // Check if river passes through this region's view area
        const inView = river.some(p =>
          p.x >= viewMinX && p.x <= viewMaxX && p.y >= viewMinY && p.y <= viewMaxY
        );
        if (!inView) continue;

        let started = false;
        for (const p of river) {
          if (p.x < viewMinX || p.x > viewMaxX || p.y < viewMinY || p.y > viewMaxY) {
            started = false;
            continue;
          }
          const px = (p.x - viewMinX) * CELL_SIZE + CELL_SIZE / 2;
          const py = (p.y - viewMinY) * CELL_SIZE + CELL_SIZE / 2;
          if (!started) { riverGfx.moveTo(px, py); started = true; }
          else riverGfx.lineTo(px, py);
        }
      }
      riverGfx.stroke({ color: 0x3a7aaa, width: 2, alpha: 0.7 });
      this._regionContainer.addChild(riverGfx);
    }

    // ── Spellroads through the region ──────────────────────────────────────
    if (world.spellroads && world.spellroads.length > 0) {
      const roadGlowGfx = new Graphics();
      const roadGfx = new Graphics();

      for (const road of world.spellroads) {
        let started = false;
        for (const p of road) {
          const gx = Math.round(p.x * world.gridW);
          const gy = Math.round(p.y * world.gridH);
          if (gx < viewMinX || gx > viewMaxX || gy < viewMinY || gy > viewMaxY) {
            started = false;
            continue;
          }
          const px = (gx - viewMinX) * CELL_SIZE + CELL_SIZE / 2;
          const py = (gy - viewMinY) * CELL_SIZE + CELL_SIZE / 2;
          if (!started) {
            roadGlowGfx.moveTo(px, py);
            roadGfx.moveTo(px, py);
            started = true;
          } else {
            roadGlowGfx.lineTo(px, py);
            roadGfx.lineTo(px, py);
          }
        }
      }

      roadGlowGfx.stroke({ color: 0xc8a020, width: 10, alpha: 0.2 });
      roadGfx.stroke({ color: 0xc8a020, width: 4, alpha: 0.85 });
      this._regionContainer.addChild(roadGlowGfx);
      this._regionContainer.addChild(roadGfx);
    }

    // ── Towns ──────────────────────────────────────────────────────────────
    const townGfx = new Graphics();
    const labelStyle = new TextStyle({
      fontFamily: 'serif',
      fontSize: 9,
      fill: 0xddccaa,
      align: 'center',
      dropShadow: { color: 0x000000, blur: 2, distance: 1, alpha: 0.9 },
    });

    for (const town of region.towns) {
      const px = (town.x - viewMinX) * CELL_SIZE + CELL_SIZE / 2;
      const py = (town.y - viewMinY) * CELL_SIZE + CELL_SIZE / 2;
      const color = town.type === 'city' ? 0xffd700 : (town.type === 'village' ? 0xaaaaaa : 0x886644);
      const radius = town.type === 'city' ? 5 : (town.type === 'village' ? 3.5 : 3);

      townGfx.circle(px, py, radius);
      townGfx.fill({ color, alpha: 0.95 });
      if (town.type === 'city') {
        townGfx.circle(px, py, radius + 2);
        townGfx.stroke({ color: 0xffd700, width: 1.5, alpha: 0.6 });
      }

      const label = new Text({ text: town.name, style: labelStyle });
      label.anchor.set(0.5, 0);
      label.x = px;
      label.y = py + radius + 2;
      this._regionContainer.addChild(label);
    }
    this._regionContainer.addChild(townGfx);

    // ── Special locations ──────────────────────────────────────────────────
    const locGfx = new Graphics();
    const locLabelStyle = new TextStyle({
      fontFamily: 'serif',
      fontSize: 8,
      fill: 0xcc9988,
      align: 'center',
      dropShadow: { color: 0x000000, blur: 2, distance: 1, alpha: 0.9 },
    });

    for (const loc of region.locations) {
      const px = (loc.x - viewMinX) * CELL_SIZE + CELL_SIZE / 2;
      const py = (loc.y - viewMinY) * CELL_SIZE + CELL_SIZE / 2;
      const color = LOCATION_COLORS[loc.type] ?? 0x888888;

      // Diamond shape
      locGfx.moveTo(px, py - 4);
      locGfx.lineTo(px + 3, py);
      locGfx.lineTo(px, py + 4);
      locGfx.lineTo(px - 3, py);
      locGfx.closePath();
      locGfx.fill({ color, alpha: 0.85 });
      locGfx.stroke({ color: 0xffffff, width: 0.5, alpha: 0.4 });

      const label = new Text({ text: loc.name, style: locLabelStyle });
      label.anchor.set(0.5, 0);
      label.x = px;
      label.y = py + 5;
      this._regionContainer.addChild(label);
    }
    this._regionContainer.addChild(locGfx);

    // ── Party token (if in this region) ───────────────────────────────────
    if (WorldState.currentRegionId === this._regionId) {
      const partyGfx = new Graphics();
      const partyRx = (region.centerX - viewMinX) * CELL_SIZE + CELL_SIZE / 2;
      const partyRy = (region.centerY - viewMinY) * CELL_SIZE + CELL_SIZE / 2;

      partyGfx.circle(partyRx, partyRy, 7);
      partyGfx.fill({ color: 0xffdd00 });
      partyGfx.circle(partyRx, partyRy, 7);
      partyGfx.stroke({ color: 0xffffff, width: 2 });
      partyGfx.moveTo(partyRx - 5, partyRy);
      partyGfx.lineTo(partyRx + 5, partyRy);
      partyGfx.moveTo(partyRx, partyRy - 5);
      partyGfx.lineTo(partyRx, partyRy + 5);
      partyGfx.stroke({ color: 0xffffff, width: 1.5 });
      this._regionContainer.addChild(partyGfx);
    }

    // ── Fog layer ──────────────────────────────────────────────────────────
    this._fogContainer = new Container();
    this._fogContainer.label = 'regionFog';
    this._regionContainer.addChild(this._fogContainer);
    this._redrawFog();
  }

  _redrawFog() {
    if (!this._fogContainer || !WorldState.world) return;

    this._fogContainer.removeChildren();

    // Skip fog rendering entirely when fog of war is disabled
    if (!window.__settings?.fogOfWar) return;

    const world = WorldState.world;
    const region = world.regions.find(r => r.id === this._regionId);
    if (!region || !this._viewOffset) return;

    const fogGfx = new Graphics();

    // Region map fog: if region not explored, fog everything
    if (!region.explored) {
      // Completely fog non-explored regions
      const { minX, maxX, minY, maxY } = this._regionBounds;
      const vox = this._viewOffset.x;
      const voy = this._viewOffset.y;

      for (let gy = minY; gy <= maxY; gy++) {
        for (let gx = minX; gx <= maxX; gx++) {
          const px = (gx - vox) * CELL_SIZE;
          const py = (gy - voy) * CELL_SIZE;
          fogGfx.rect(px, py, CELL_SIZE, CELL_SIZE);
          fogGfx.fill({ color: 0x000000, alpha: 0.85 });
        }
      }
    } else {
      // Per-cell fog within the region based on local map fog state
      for (const c of region.cells) {
        const fogState = WorldState.getFogAt(this._regionId, c.x, c.y);
        if (fogState === 2) continue; // fully revealed

        const px = (c.x - this._viewOffset.x) * CELL_SIZE;
        const py = (c.y - this._viewOffset.y) * CELL_SIZE;
        const alpha = fogState === 0 ? 0.75 : 0.35;

        fogGfx.rect(px, py, CELL_SIZE, CELL_SIZE);
        fogGfx.fill({ color: 0x000000, alpha });
      }
    }

    this._fogContainer.addChild(fogGfx);
  }

  // ─── Camera ─────────────────────────────────────────────────────────────────

  _centerCamera() {
    if (!WorldState.world || !this._regionBounds) return;

    const { minX, maxX, minY, maxY } = this._regionBounds;
    const RING_EXPAND = 3;
    const mapW = (maxX - minX + 1 + RING_EXPAND * 2) * CELL_SIZE;
    const mapH = (maxY - minY + 1 + RING_EXPAND * 2) * CELL_SIZE;

    const vw = this._renderer.width;
    const vh = this._renderer.height;

    const scaleX = vw / mapW;
    const scaleY = vh / mapH;
    const zoom = Math.min(scaleX, scaleY, 3) * 0.9;

    this._camera.zoom = zoom;
    this._camera.x = (vw - mapW * zoom) / 2;
    this._camera.y = (vh - mapH * zoom) / 2;

    this._applyCamera();
  }

  _applyCamera() {
    if (!this._regionContainer) return;
    this._regionContainer.x = this._camera.x;
    this._regionContainer.y = this._camera.y;
    this._regionContainer.scale.set(this._camera.zoom);
  }

  // ─── Input ───────────────────────────────────────────────────────────────────

  _bindInput() {
    const canvas = document.getElementById('game-canvas');
    if (!canvas) return;

    this._onPointerDown = (e) => {
      if (e.button === 0) {
        this._isDragging = true;
        this._dragStart = { x: e.clientX, y: e.clientY };
        this._dragCameraStart = { x: this._camera.x, y: this._camera.y };
        this._dragMoved = false;
      }
    };

    this._onPointerMove = (e) => {
      if (!this._isDragging) return;
      const dx = e.clientX - this._dragStart.x;
      const dy = e.clientY - this._dragStart.y;
      if (Math.abs(dx) > 3 || Math.abs(dy) > 3) this._dragMoved = true;
      this._camera.x = this._dragCameraStart.x + dx;
      this._camera.y = this._dragCameraStart.y + dy;
      this._applyCamera();
    };

    this._onPointerUp = () => {
      this._isDragging = false;
    };

    this._onWheel = (e) => {
      e.preventDefault();
      const zoomFactor = e.deltaY > 0 ? 0.9 : 1.1;
      const newZoom = Math.max(0.3, Math.min(8, this._camera.zoom * zoomFactor));
      const rect = canvas.getBoundingClientRect();
      const mx = e.clientX - rect.left;
      const my = e.clientY - rect.top;
      this._camera.x = mx - (mx - this._camera.x) * (newZoom / this._camera.zoom);
      this._camera.y = my - (my - this._camera.y) * (newZoom / this._camera.zoom);
      this._camera.zoom = newZoom;
      this._applyCamera();
    };

    canvas.addEventListener('pointerdown', this._onPointerDown);
    window.addEventListener('pointermove', this._onPointerMove);
    window.addEventListener('pointerup', this._onPointerUp);
    canvas.addEventListener('wheel', this._onWheel, { passive: false });
  }

  // ─── HTML Panel ──────────────────────────────────────────────────────────────

  _buildHTMLPanel() {
    const existing = document.getElementById('panel-region-map-info');
    if (existing) existing.remove();

    const panel = document.createElement('div');
    panel.id = 'panel-region-map-info';

    const world = WorldState.world;
    const region = world?.regions.find(r => r.id === this._regionId);

    const locationItems = region?.locations.map(loc => {
      const color = LOCATION_COLORS[loc.type] ?? '#888';
      const colorHex = '#' + color.toString(16).padStart(6, '0');
      return `<li style="color:${colorHex}; font-size:11px;">
        ${loc.name} <span style="color:#776655">(${loc.type.replace('_', ' ')})</span>
      </li>`;
    }).join('') ?? '';

    panel.style.cssText = `
      position: fixed;
      bottom: 16px;
      left: 16px;
      width: 280px;
      background: rgba(12, 8, 4, 0.88);
      border: 1px solid #5a4a2a;
      border-radius: 4px;
      padding: 12px 14px;
      color: #ddccaa;
      font-family: serif;
      font-size: 13px;
      z-index: 100;
      pointer-events: auto;
      box-shadow: 0 4px 16px rgba(0,0,0,0.6);
    `;

    panel.innerHTML = `
      <div style="font-size:15px; font-weight:bold; color:#e8d8a0; margin-bottom:4px;">
        ${region?.name ?? 'Unknown Region'}
      </div>
      <div style="font-size:11px; color:#9a8a6a; margin-bottom:8px;">
        Level ${region?.level ?? '?'} &nbsp;|&nbsp; ${(region?.biome ?? 'unknown').replace('_', ' ')}
      </div>
      ${locationItems ? `
        <div style="font-size:11px; color:#7a6a4a; margin-bottom:2px;">Locations:</div>
        <ul style="margin:0 0 8px 14px; padding:0; list-style:disc; max-height:80px; overflow-y:auto;">
          ${locationItems}
        </ul>
      ` : ''}
      <div style="margin-top:8px; border-top:1px solid #3a2a0a; padding-top:8px; display:flex; gap:6px;">
        <button id="btn-region-enter-local" style="
          background:#1a3a0a; border:1px solid #3a7a2a; color:#aaddaa;
          padding:5px 10px; cursor:pointer; font-size:12px; font-family:serif;
          border-radius:3px; flex:1;
        ">Enter Local Map</button>
        <button id="btn-region-world-map" style="
          background:#1a1208; border:1px solid #5a4a2a; color:#aaa;
          padding:5px 10px; cursor:pointer; font-size:11px; font-family:serif;
          border-radius:3px; flex:1;
        ">World Map</button>
      </div>
    `;

    document.body.appendChild(panel);
    this._panel = panel;

    document.getElementById('btn-region-enter-local')?.addEventListener('click', () => {
      SceneManager.transition('localMap', { regionId: this._regionId });
    });
    document.getElementById('btn-region-world-map')?.addEventListener('click', () => {
      SceneManager.transition('worldMap');
    });
  }

  _removeHTMLPanel() {
    if (this._panel) {
      this._panel.remove();
      this._panel = null;
    }
  }

  // ─── Lifecycle ───────────────────────────────────────────────────────────────

  update(_deltaTime) {}

  async destroy() {
    if (this._regionContainer) {
      this._renderer.layers.world.removeChild(this._regionContainer);
      this._regionContainer.destroy({ children: true });
      this._regionContainer = null;
    }

    this._removeHTMLPanel();

    const canvas = document.getElementById('game-canvas');
    if (canvas) {
      if (this._onPointerDown) canvas.removeEventListener('pointerdown', this._onPointerDown);
      if (this._onWheel) canvas.removeEventListener('wheel', this._onWheel);
    }
    if (this._onPointerMove) window.removeEventListener('pointermove', this._onPointerMove);
    if (this._onPointerUp)   window.removeEventListener('pointerup', this._onPointerUp);

    if (this._resizeUnsub) { this._resizeUnsub(); this._resizeUnsub = null; }
    if (this._fogUpdateUnsub) { this._fogUpdateUnsub(); this._fogUpdateUnsub = null; }

    DebugLog.info('[world] RegionMapScene destroyed');
  }
}
